import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [showDecrypted, setShowDecrypted] = useState(false);
    const navigate = useNavigate();

    const role = localStorage.getItem("role"); // 👈 get role from localStorage

    const fetchLeads = async (decrypted = false) => {
        const token = localStorage.getItem("token");
        if (!token) {
            navigate("/");
            return;
        }

        try {
            const res = await axios.get("http://localhost:8000/leads", {
                headers: { Authorization: `Bearer ${token}` },
                params: { decrypted: decrypted ? 1 : 0 }, // 🔹 send flag to backend
            });
            setLeads(res.data || []);
        } catch (err) {
            console.error("Error fetching leads:", err);
            if (err.response && err.response.status === 401) {
                setError("Session expired. Please log in again.");
                localStorage.removeItem("token");
                localStorage.removeItem("role");
                navigate("/");
            } else {
                setError("Failed to load leads. Please try again later.");
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLeads(showDecrypted);
    }, [navigate, showDecrypted]);

    return (
        <div className="container mt-4">
            <div className="d-flex justify-content-between align-items-center mb-3">
                <h2 className="mb-0">Leads</h2>

                {/* 👇 Show button only for admin and agent */}
                {(role === "admin" || role === "agent") && (
                    <button
                        className="btn btn-primary"
                        onClick={() => setShowDecrypted((prev) => !prev)}
                    >
                        {showDecrypted ? "Show Encrypted" : "Show Decrypted"}
                    </button>
                )}
            </div>

            {leads.length > 0 ? (
                <table className="table table-striped table-bordered">
                    <thead className="table-dark">
                        <tr>
                            <th>Name</th>
                            <th>Username</th>
                            <th>Email</th>
                            <th>Phone</th>
                            <th>Company URL</th>
                            <th>Company Name</th>
                        </tr>
                    </thead>
                    <tbody>
                        {leads.map((lead) => (
                            <tr key={lead.id}>
                                <td>{lead.name || "-"}</td>
                                <td>{lead.username || "-"}</td>
                                <td>{lead.email || "-"}</td>
                                <td>{lead.phone || "-"}</td>
                                <td>{lead.link_url || "-"}</td>
                                <td>{lead.company_name || "-"}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            ) : (
                <p className="text-muted">No leads found.</p>
            )}
        </div>
    );
}

export default Leads;
